    margin: 0;
    font-size: var(--mrg-semantic-font-size-heading-medium);
    font-weight: var(--mrg-semantic-font-weight-heading);
    line-height: var(--mrg-semantic-font-line-height-heading);
    text-wrap: balance;
  }

  .mrg-crud-data-workspace [data-slot="crud-data-workspace-heading"] p {
    max-inline-size: var(--mrg-semantic-size-content-prose);
    margin-block: var(--mrg-semantic-space-stack-xs) 0;
    color: var(--mrg-semantic-color-foreground-muted);
    line-height: var(--mrg-semantic-font-line-height-body);
  }

  .mrg-crud-data-workspace [data-slot="crud-data-workspace-tools"] {
    display: flex;
    flex-wrap: wrap;
    align-items: end;
    gap: var(--mrg-semantic-space-inline-sm);
    padding: var(--mrg-semantic-space-inset-sm);
    border-block: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-crud-data-workspace [data-slot="crud-data-workspace-tools"] label,
